# Module providing data structures and classes implementing types_module interfaces
from types_module import IIdentifiable, ITrackable, Status, Priority

# Simple struct for coordinates
struct Point2D:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def magnitude(self) -> float:
        return (self.x ** 2 + self.y ** 2) ** 0.5

# Task implementing interfaces
class Task(IIdentifiable, ITrackable):
    id: int
    title: str
    status: Status
    priority: Priority
    parent_id: int?

    def __init__(self, id: int, title: str):
        self.id = id
        self.title = title
        self.status = Status.PENDING
        self.priority = Priority.MEDIUM
        self.parent_id = None

    def get_id(self) -> int:
        return self.id

    def get_name(self) -> str:
        return self.title

    def get_status(self) -> Status:
        return self.status

    def set_status(self, status: Status) -> None:
        self.status = status

    def set_priority(self, priority: Priority) -> None:
        self.priority = priority

    def set_parent(self, parent_id: int) -> None:
        self.parent_id = Some(parent_id)

    @virtual
    def describe(self) -> str:
        return "Task: " + self.title

# FinalizedTask with @final decorator
@final
class FinalizedTask(Task):
    completed_at: str

    def __init__(self, id: int, title: str, completed_at: str):
        super().__init__(id, title)
        self.completed_at = completed_at
        self.set_status(Status.COMPLETED)

    @override
    def describe(self) -> str:
        return "Completed Task: " + self.title

# Factory function for creating tasks
def create_task(id: int, title: str) -> Task:
    return Task(id, title)

def create_point(x: float, y: float) -> Point2D:
    return Point2D(x, y)

