# Utility module with helper functions
from data_module import Point2D
from types_module import Status, Priority, IIdentifiable

# Constants at module level
MAX_RETRY_COUNT: int = 5
DEFAULT_TIMEOUT: float = 30.0

# Higher-order function applying an operation multiple times
def apply_n_times(value: int, operation: (int) -> int, n: int) -> int:
    result: int = value
    i: int = 0
    while i < n:
        result = operation(result)
        i += 1
    return result

# Function with default and keyword parameter support
def format_status_message(status: Status, prefix: str = "Status") -> str:
    status_str: str = "Unknown"
    if status == Status.PENDING:
        status_str = "Pending"
    elif status == Status.ACTIVE:
        status_str = "Active"
    elif status == Status.COMPLETED:
        status_str = "Completed"
    elif status == Status.CANCELLED:
        status_str = "Cancelled"
    return prefix + ": " + status_str

# Result type for error handling
def parse_priority(value: str) -> Priority !str:
    if value == "LOW":
        return Ok(Priority.LOW)
    elif value == "MEDIUM":
        return Ok(Priority.MEDIUM)
    elif value == "HIGH":
        return Ok(Priority.HIGH)
    elif value == "CRITICAL":
        return Ok(Priority.CRITICAL)
    else:
        return Err("Invalid priority")

# Function returning list of lambda functions
def get_transformers() -> list[(int) -> int]:
    result: list[(int) -> int] = list()
    double: (int) -> int = lambda x: x * 2
    triple: (int) -> int = lambda x: x * 3
    increment: (int) -> int = lambda x: x + 1
    result.append(double)
    result.append(triple)
    result.append(increment)
    return result

# List comprehension helper
def get_even_numbers(n: int) -> list[int]:
    return [x for x in range(n) if x % 2 == 0]

# Dict comprehension helper
def create_number_dict(keys: list[str]) -> dict[str, int]:
    return {k: len(k) for k in keys}

# Safe get id with nullable
def safe_get_id(item: IIdentifiable?) -> int:
    if item is not None:
        return item.get_id()
    return -1
